import { mkdir, readFile, writeFile } from "node:fs/promises";
import { homedir } from "node:os";
import { dirname, join, resolve } from "node:path";

const CONFIG_DIRECTORY_NAME = ".building-agent";
const CONFIG_FILE_NAME = "config.json";

export interface CliConfig {
  apiUrl?: string;
  token?: string;
  selectedProjectId?: string;
}

export interface ConfigStoreOptions {
  homeDir?: string;
  env?: NodeJS.ProcessEnv;
}

export interface ConfigDiagnostics {
  cliHomeDir: string;
  configPath: string;
}

export class CliConfigError extends Error {
  readonly code: "config_parse_failed" | "config_read_failed" | "config_write_failed";
  readonly diagnostics: ConfigDiagnostics;

  constructor(
    code: CliConfigError["code"],
    message: string,
    diagnostics: ConfigDiagnostics,
    cause?: unknown
  ) {
    super(message, { cause });
    this.name = "CliConfigError";
    this.code = code;
    this.diagnostics = diagnostics;
  }

  toJSON(): { error: { code: string; message: string; cliHomeDir: string; configPath: string } } {
    return {
      error: {
        code: this.code,
        message: this.message,
        cliHomeDir: this.diagnostics.cliHomeDir,
        configPath: this.diagnostics.configPath
      }
    };
  }
}

function configuredHomeDir(options: ConfigStoreOptions = {}): string {
  const env = options.env ?? process.env;
  return options.homeDir ?? env.BUILDING_AGENT_CLI_HOME ?? homedir();
}

export function getConfigDiagnostics(options: ConfigStoreOptions = {}): ConfigDiagnostics {
  const cliHomeDir = resolve(configuredHomeDir(options));
  return {
    cliHomeDir,
    configPath: join(cliHomeDir, CONFIG_DIRECTORY_NAME, CONFIG_FILE_NAME)
  };
}

function assertPlainConfig(value: unknown, diagnostics: ConfigDiagnostics): CliConfig {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    throw new CliConfigError("config_parse_failed", "CLI config file must contain a JSON object.", diagnostics);
  }

  const candidate = value as Record<string, unknown>;
  for (const key of ["apiUrl", "token", "selectedProjectId"] as const) {
    if (candidate[key] !== undefined && typeof candidate[key] !== "string") {
      throw new CliConfigError("config_parse_failed", `CLI config field ${key} must be a string.`, diagnostics);
    }
  }

  return {
    ...(typeof candidate.apiUrl === "string" ? { apiUrl: candidate.apiUrl } : {}),
    ...(typeof candidate.token === "string" ? { token: candidate.token } : {}),
    ...(typeof candidate.selectedProjectId === "string" ? { selectedProjectId: candidate.selectedProjectId } : {})
  };
}

export async function loadConfig(options: ConfigStoreOptions = {}): Promise<CliConfig> {
  const diagnostics = getConfigDiagnostics(options);

  try {
    const raw = await readFile(diagnostics.configPath, "utf8");
    return assertPlainConfig(JSON.parse(raw) as unknown, diagnostics);
  } catch (error) {
    if (error instanceof CliConfigError) {
      throw error;
    }

    if (error instanceof SyntaxError) {
      throw new CliConfigError("config_parse_failed", "CLI config file contains malformed JSON.", diagnostics, error);
    }

    if (typeof error === "object" && error !== null && "code" in error && error.code === "ENOENT") {
      return {};
    }

    throw new CliConfigError("config_read_failed", "Failed to read CLI config file.", diagnostics, error);
  }
}

export async function saveConfig(config: CliConfig, options: ConfigStoreOptions = {}): Promise<ConfigDiagnostics> {
  const diagnostics = getConfigDiagnostics(options);
  const safeConfig = assertPlainConfig(config, diagnostics);

  try {
    await mkdir(dirname(diagnostics.configPath), { recursive: true, mode: 0o700 });
    await writeFile(diagnostics.configPath, `${JSON.stringify(safeConfig, null, 2)}\n`, { mode: 0o600 });
    return diagnostics;
  } catch (error) {
    throw new CliConfigError("config_write_failed", "Failed to write CLI config file.", diagnostics, error);
  }
}

export function redactConfig(config: CliConfig): CliConfig {
  return {
    ...config,
    ...(config.token ? { token: "[redacted]" } : {})
  };
}

import { describe, expect, it } from "vitest";
import { mkdtemp, readFile, rm } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { loadConfig, redactConfig, saveConfig, CliConfigError, getConfigDiagnostics } from "./config.js";

describe("cli config store", () => {
  it("uses an isolated home directory and never touches the real home", async () => {
    const homeDir = await mkdtemp(join(tmpdir(), "building-agent-cli-"));
    const diagnostics = await saveConfig(
      { apiUrl: "http://127.0.0.1:3000", token: "secret-token", selectedProjectId: "proj_1" },
      { homeDir }
    );

    expect(diagnostics.cliHomeDir).toBe(homeDir);
    expect(diagnostics.configPath).toBe(join(homeDir, ".building-agent", "config.json"));
    await expect(readFile(join(homeDir, ".building-agent", "config.json"), "utf8")).resolves.toContain(
      "selectedProjectId"
    );
    await expect(loadConfig({ homeDir })).resolves.toEqual({
      apiUrl: "http://127.0.0.1:3000",
      token: "secret-token",
      selectedProjectId: "proj_1"
    });
    await rm(homeDir, { recursive: true, force: true });
  });

  it("surfaces redaction-safe diagnostics for malformed config", async () => {
    const homeDir = await mkdtemp(join(tmpdir(), "building-agent-cli-"));
    const diagnostics = getConfigDiagnostics({ homeDir });
    await saveConfig({ token: "top-secret" }, { homeDir });
    await expect(readFile(diagnostics.configPath, "utf8")).resolves.toContain("top-secret");

    await expect(saveConfig({ token: 1 as never }, { homeDir })).rejects.toMatchObject({
      code: "config_parse_failed",
      diagnostics: {
        cliHomeDir: homeDir,
        configPath: diagnostics.configPath
      }
    });

    const error = new CliConfigError(
      "config_write_failed",
      "Failed to write CLI config file.",
      diagnostics,
      new Error("boom")
    );
    expect(error.toJSON()).toEqual({
      error: {
        code: "config_write_failed",
        message: "Failed to write CLI config file.",
        cliHomeDir: homeDir,
        configPath: diagnostics.configPath
      }
    });

    expect(redactConfig({ apiUrl: "x", token: "secret" })).toEqual({ apiUrl: "x", token: "[redacted]" });
    await rm(homeDir, { recursive: true, force: true });
  });
});

#!/usr/bin/env node
import { CliConfigError, getConfigDiagnostics, loadConfig, redactConfig } from "./config.js";

function printJson(value: unknown): void {
  process.stdout.write(`${JSON.stringify(value, null, 2)}\n`);
}

async function main(argv: string[]): Promise<number> {
  const [command] = argv;

  if (!command || command === "help" || command === "--help") {
    process.stdout.write("building-agent <session|config-path>\n");
    return 0;
  }

  if (command === "config-path") {
    printJson(getConfigDiagnostics());
    return 0;
  }

  if (command === "session") {
    const diagnostics = getConfigDiagnostics();
    const config = await loadConfig();
    printJson({ diagnostics, config: redactConfig(config) });
    return 0;
  }

  process.stderr.write(`Unknown command: ${command}\n`);
  return 2;
}

try {
  process.exitCode = await main(process.argv.slice(2));
} catch (error) {
  if (error instanceof CliConfigError) {
    process.stderr.write(`${JSON.stringify(error.toJSON())}\n`);
    process.exitCode = 1;
  } else {
    process.stderr.write(`${error instanceof Error ? error.message : "Unknown CLI error"}\n`);
    process.exitCode = 1;
  }
}

